CREATE TABLE "roles" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL UNIQUE, "description" TEXT);
CREATE TABLE "users" ("id" TEXT NOT NULL PRIMARY KEY, "email" TEXT NOT NULL UNIQUE, "password" TEXT NOT NULL, "firstName" TEXT NOT NULL, "lastName" TEXT NOT NULL, "avatar" TEXT, "roleId" TEXT NOT NULL, "isActive" BOOLEAN NOT NULL DEFAULT true, "lastLoginAt" TIMESTAMP, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("roleId") REFERENCES "roles"("id"));
CREATE TABLE "permissions" ("id" TEXT NOT NULL PRIMARY KEY, "roleId" TEXT NOT NULL, "resource" TEXT NOT NULL, "action" TEXT NOT NULL, FOREIGN KEY ("roleId") REFERENCES "roles"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "permissions_roleId_resource_action_key" ON "permissions"("roleId", "resource", "action");
CREATE TABLE "employees" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL UNIQUE, "employeeId" TEXT NOT NULL UNIQUE, "position" TEXT NOT NULL, "department" TEXT NOT NULL, "phone" TEXT, "hireDate" TIMESTAMP NOT NULL, "salary" REAL, "skills" TEXT, "address" TEXT, "emergencyContact" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE);
CREATE TABLE "chats" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "description" TEXT, "type" TEXT NOT NULL DEFAULT 'group', "createdBy" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("createdBy") REFERENCES "users"("id"));
CREATE TABLE "chat_members" ("id" TEXT NOT NULL PRIMARY KEY, "chatId" TEXT NOT NULL, "userId" TEXT NOT NULL, "joinedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("chatId") REFERENCES "chats"("id") ON DELETE CASCADE, FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "chat_members_chatId_userId_key" ON "chat_members"("chatId", "userId");
CREATE TABLE "chat_messages" ("id" TEXT NOT NULL PRIMARY KEY, "chatId" TEXT NOT NULL, "userId" TEXT NOT NULL, "content" TEXT NOT NULL, "type" TEXT NOT NULL DEFAULT 'text', "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("chatId") REFERENCES "chats"("id") ON DELETE CASCADE, FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE);
CREATE TABLE "info_banks" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "description" TEXT, "category" TEXT, "tags" TEXT, "createdBy" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "info_items" ("id" TEXT NOT NULL PRIMARY KEY, "bankId" TEXT NOT NULL, "title" TEXT NOT NULL, "content" TEXT, "tags" TEXT, "createdBy" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("bankId") REFERENCES "info_banks"("id") ON DELETE CASCADE);
CREATE TABLE "crm_templates" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "description" TEXT, "modules" TEXT, "config" TEXT, "createdBy" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "crm_exports" ("id" TEXT NOT NULL PRIMARY KEY, "templateId" TEXT NOT NULL, "format" TEXT NOT NULL, "content" TEXT NOT NULL, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("templateId") REFERENCES "crm_templates"("id") ON DELETE CASCADE);
CREATE TABLE "analytics_dashboards" ("id" TEXT NOT NULL PRIMARY KEY, "name" TEXT NOT NULL, "createdBy" TEXT NOT NULL, "config" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "analytics_widgets" ("id" TEXT NOT NULL PRIMARY KEY, "dashboardId" TEXT NOT NULL, "type" TEXT NOT NULL, "title" TEXT NOT NULL, "config" TEXT, "position" TEXT, "dataSource" TEXT NOT NULL, "refreshInterval" INTEGER, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("dashboardId") REFERENCES "analytics_dashboards"("id") ON DELETE CASCADE);
CREATE TABLE "notifications" ("id" TEXT NOT NULL PRIMARY KEY, "userId" TEXT NOT NULL, "title" TEXT NOT NULL, "message" TEXT NOT NULL, "type" TEXT NOT NULL, "isRead" BOOLEAN NOT NULL DEFAULT false, "data" TEXT, "createdAt" TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY ("userId") REFERENCES "users"("id") ON DELETE CASCADE);
